      code: "#include <bits/stdc++.h>\nusing namespace std;\n\n// 例 3.11 靶形數獨（洛谷 P1074）：填满數獨，最大化 sum(格分值 * 格內數字)，\n// 分值由离中心的距离决定（中心 10 分，向外每圈少 1 分，最外圈 6 分）。\n// 用最少候选優先（MRV）挑选待填格子進行剪枝。\nint grid[9][9];\nint score_of[9][9];\nint row_mask[9], col_mask[9], box_mask[9];\nint best = -1;\n\nint box_id(int r, int c) { return r / 3 * 3 + c / 3; }\n\nvoid dfs(int filled, int total) {\n    if (filled == 81) {\n        best = max(best, total);\n        return;\n    }\n    // 選擇候选數最少的空格。\n    int br = -1, bc = -1, bcand = -1, fewest = 100;\n    for (int r = 0; r < 9; ++r) {\n        for (int c = 0; c < 9; ++c) {\n            if (grid[r][c] == 0) {\n                int used = row_mask[r] | col_mask[c] | box_mask[box_id(r, c)];\n                int cand = (~used) & 0x3FE;  // 位 1..9\n                int count = __builtin_popcount(cand);\n                if (count == 0) { return; } // 該空格無解，剪枝\n                if (count < fewest) {\n                    fewest = count;\n                    br = r;\n                    bc = c;\n                    bcand = cand;\n                }\n            }\n        }\n    }\n    int b = box_id(br, bc);\n    for (int v = 1; v <= 9; ++v) {\n        int bit = 1 << v;\n        if (!(bcand & bit)) { continue; }\n        grid[br][bc] = v;\n        row_mask[br] |= bit;\n        col_mask[bc] |= bit;\n        box_mask[b] |= bit;\n        dfs(filled + 1, total + score_of[br][bc] * v);\n        grid[br][bc] = 0;\n        row_mask[br] &= ~bit;\n        col_mask[bc] &= ~bit;\n        box_mask[b] &= ~bit;\n    }\n}\n\nint main() {\n    for (int r = 0; r < 9; ++r) {\n        for (int c = 0; c < 9; ++c) {\n            int ring = min(min(r, 8 - r), min(c, 8 - c));\n            score_of[r][c] = 6 + ring;\n        }\n    }\n    for (int r = 0; r < 9; ++r) {\n        for (int c = 0; c < 9; ++c) {\n            if (!(cin >> grid[r][c])) { return 0; }\n            if (grid[r][c] != 0) {\n                int bit = 1 << grid[r][c];\n                row_mask[r] |= bit;\n                col_mask[c] |= bit;\n                box_mask[box_id(r, c)] |= bit;\n            }\n        }\n    }\n    int base = 0;\n    int filled = 0;\n    for (int r = 0; r < 9; ++r) {\n        for (int c = 0; c < 9; ++c) {\n            if (grid[r][c] != 0) {\n                base += score_of[r][c] * grid[r][c];\n                ++filled;\n            }\n        }\n    }\n    dfs(filled, base);\n    cout << best << '\\n';\n    return 0;\n}\n"
