        '問題描述：不含前導 0 且相鄰兩位數字之差至少為 2 的正整數稱為 Windy 數。問在 a 和 b 之間（包括 a 和 b），總共有多少個 Windy 數？（特例：把一位數 0~9 看成 Windy 數）\n輸入：兩個整數 a 和 b，1 ≤ a ≤ b ≤ 2×10^9。\n輸出：一個整數，表示答案。\n輸入樣例：25 50\n輸出樣例：20',
      idea: '數位 DP：求 [a,b] 轉為 count(b) − count(a−1)。記憶化搜尋逐位填數，狀態為 (位置, 前一位數字)，並用 lead 處理前導 0、limit 處理數位上界。',
      complexity: '時間 O(位數 × 10 × 10)，空間 O(位數 × 10)。',
      code: "#include <bits/stdc++.h>\nusing namespace std;\n\n// 例 5.5 Windy 數（洛谷 P2657）：统計 [a, b] 內相邻兩位數字之差至少為 2 且无前導 0 的數\nlong long dp[11][11];\nint digits[11];\n\nlong long dfs(int pos, int last, bool lead, bool limit) {\n    if (pos == 0) { return 1; }\n    if (!lead && !limit && dp[pos][last] != -1) { return dp[pos][last]; }\n    int up = limit ? digits[pos] : 9;\n    long long res = 0;\n    for (int d = 0; d <= up; ++d) {\n        if (!lead && abs(d - last) < 2) { continue; }\n        res += dfs(pos - 1, (lead && d == 0) ? -2 : d,\n                   lead && d == 0, limit && d == up);\n    }\n    if (!lead && !limit) { dp[pos][last] = res; }\n    return res;\n}\n\nlong long count_windy(long long x) {\n    if (x < 0) { return 0; }\n    int len = 0;\n    while (x > 0) {\n        digits[++len] = static_cast<int>(x % 10);\n        x /= 10;\n    }\n    memset(dp, -1, sizeof(dp));\n    return dfs(len, -2, true, true);\n}\n\nint main() {\n    long long a, b;\n    if (!(cin >> a >> b)) { return 0; }\n    cout << count_windy(b) - count_windy(a - 1) << '\\n';\n    return 0;\n}\n"
